import { useState } from 'react';
import {
    Box,
    Paper,
    IconButton,
    Typography,
} from '@mui/material';
import {
    AddPhotoAlternate as AddPhotoIcon,
    Delete as DeleteIcon,
    Edit as EditIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import ImageEditor from './ImageEditor';

const MotionPaper = motion(Paper);

const PhotoBookPage = ({ format, photos, onPhotoAdd, onPhotoRemove, onPhotoEdit, pageNumber }) => {
    const [isEditorOpen, setIsEditorOpen] = useState(false);
    const [selectedPhoto, setSelectedPhoto] = useState(null);
    const [dropTarget, setDropTarget] = useState(null);

    // Вычисляем размеры страницы на основе формата
    const getPageDimensions = () => {
        const baseWidth = 600; // Базовая ширина для отображения
        const [width, height] = format.size.split('×').map(dim => parseInt(dim));
        const ratio = height / width;
        return {
            width: baseWidth,
            height: baseWidth * ratio
        };
    };

    const handleDragOver = (e, position) => {
        e.preventDefault();
        setDropTarget(position);
    };

    const handleDragLeave = () => {
        setDropTarget(null);
    };

    const handleDrop = (e, position) => {
        e.preventDefault();
        const photoId = e.dataTransfer.getData('photo/id');
        if (photoId) {
            const photo = photos.find(p => p.id === photoId);
            if (photo) {
                onPhotoAdd(pageNumber, position, photo);
            }
        }
        setDropTarget(null);
    };

    const handleEdit = (photo) => {
        setSelectedPhoto(photo);
        setIsEditorOpen(true);
    };

    const handleEditorClose = () => {
        setIsEditorOpen(false);
        setSelectedPhoto(null);
    };

    const handlePhotoSave = (editedBlob) => {
        if (selectedPhoto) {
            onPhotoEdit(pageNumber, selectedPhoto.position, editedBlob);
        }
        handleEditorClose();
    };

    const { width, height } = getPageDimensions();

    return (
        <Box sx={{ mb: 4 }}>
            <Typography variant="h6" gutterBottom align="center">
                Страница {pageNumber + 1}
            </Typography>
            <MotionPaper
                elevation={3}
                sx={{
                    width,
                    height,
                    margin: '0 auto',
                    position: 'relative',
                    backgroundColor: '#fff',
                    display: 'grid',
                    gridTemplateColumns: 'repeat(2, 1fr)',
                    gridTemplateRows: 'repeat(2, 1fr)',
                    gap: 2,
                    padding: 2
                }}
            >
                {Array.from({ length: 4 }).map((_, index) => (
                    <Box
                        key={index}
                        sx={{
                            border: '2px dashed',
                            borderColor: dropTarget === index ? 'primary.main' : 'grey.300',
                            borderRadius: 1,
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            position: 'relative',
                            transition: 'all 0.2s',
                            '&:hover': {
                                borderColor: 'primary.main'
                            }
                        }}
                        onDragOver={(e) => handleDragOver(e, index)}
                        onDragLeave={handleDragLeave}
                        onDrop={(e) => handleDrop(e, index)}
                    >
                        {photos.find(p => p.position === index) ? (
                            <Box sx={{ position: 'relative', width: '100%', height: '100%' }}>
                                <img
                                    src={photos.find(p => p.position === index).preview}
                                    alt={`Photo ${index + 1}`}
                                    style={{
                                        width: '100%',
                                        height: '100%',
                                        objectFit: 'cover'
                                    }}
                                />
                                <Box
                                    sx={{
                                        position: 'absolute',
                                        top: 0,
                                        right: 0,
                                        display: 'flex',
                                        gap: 1,
                                        padding: 1
                                    }}
                                >
                                    <IconButton
                                        size="small"
                                        onClick={() => handleEdit(photos.find(p => p.position === index))}
                                        sx={{ bgcolor: 'white' }}
                                    >
                                        <EditIcon fontSize="small" />
                                    </IconButton>
                                    <IconButton
                                        size="small"
                                        onClick={() => onPhotoRemove(pageNumber, index)}
                                        sx={{ bgcolor: 'white' }}
                                    >
                                        <DeleteIcon fontSize="small" />
                                    </IconButton>
                                </Box>
                            </Box>
                        ) : (
                            <AddPhotoIcon color="action" sx={{ fontSize: 40 }} />
                        )}
                    </Box>
                ))}
            </MotionPaper>

            {selectedPhoto && (
                <ImageEditor
                    open={isEditorOpen}
                    onClose={handleEditorClose}
                    image={selectedPhoto.file}
                    onSave={handlePhotoSave}
                />
            )}
        </Box>
    );
};

export default PhotoBookPage;
